import { sqliteTable, text, integer } from 'drizzle-orm/sqlite-core'

// ─── Blog Posts ──────────────────────────────────────────────────────────────

export const blogPosts = sqliteTable('blog_posts', {
  id: text('id').primaryKey(),
  slug: text('slug').notNull().unique(),
  title: text('title').notNull(),
  content: text('content').notNull(),
  translations: text('translations'),
  status: text('status', { enum: ['draft', 'published', 'archived'] })
    .notNull()
    .default('draft'),
  heroImageUrl: text('hero_image_url'),
  seoTitle: text('seo_title'),
  seoDesc: text('seo_desc'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Social Posts ────────────────────────────────────────────────────────────

export const socialPosts = sqliteTable('social_posts', {
  id: text('id').primaryKey(),
  platform: text('platform', { enum: ['instagram', 'linkedin', 'facebook'] }).notNull(),
  content: text('content').notNull(),
  scheduledAt: integer('scheduled_at', { mode: 'timestamp' }),
  status: text('status', { enum: ['pending', 'published', 'cancelled'] })
    .notNull()
    .default('pending'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── Business Config ─────────────────────────────────────────────────────────

export const businessConfig = sqliteTable('business_config', {
  id: text('id').primaryKey().default('config'),
  hours: text('hours'),
  contact: text('contact'),
  address: text('address'),
  seo: text('seo'),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Analytics ───────────────────────────────────────────────────────────────

export const analytics = sqliteTable('analytics', {
  id: text('id').primaryKey(),
  eventType: text('event_type').notNull(),
  page: text('page'),
  sessionId: text('session_id'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── Forms ──────────────────────────────────────────────────────────────────

export const forms = sqliteTable('forms', {
  id: text('id').primaryKey(),
  slug: text('slug').notNull().unique(),
  name: text('name').notNull(),
  description: text('description'),
  fields: text('fields').notNull(), // JSON array of FormField[]
  settings: text('settings'), // JSON FormSettings object
  status: text('status', { enum: ['active', 'archived'] }).notNull().default('active'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Form Submissions ──────────────────────────────────────────────────────

export const formSubmissions = sqliteTable('form_submissions', {
  id: text('id').primaryKey(),
  formId: text('form_id').notNull(),
  data: text('data').notNull(), // JSON object of field values
  metadata: text('metadata'), // JSON: IP, user agent, referrer
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── Schema Version ─────────────────────────────────────────────────────────

export const schemaVersion = sqliteTable('_schema_version', {
  id: text('id').primaryKey().default('version'),
  version: integer('version').notNull(),
  migratedAt: integer('migrated_at', { mode: 'timestamp' }).notNull(),
})
