import { handleContent } from './routes/content'
import { handleConfig } from './routes/config'
import { handleForms } from './routes/forms'
import { handleJobs } from './routes/jobs'
import { handleAnalytics } from './routes/analytics'

export interface GrowthEngineHandlerOptions {
	brainApiKey: string
	tursoUrl: string
	tursoAuthToken: string
}

function resolveRoute(pathname: string): string | null {
	// Strip the /api/rs prefix to get the route segment
	const match = pathname.match(/\/api\/rs\/(.+)/)
	if (!match?.[1]) return null
	return match[1]
}

export function GrowthEngineHandler(options: GrowthEngineHandlerOptions) {
	const { brainApiKey, tursoUrl, tursoAuthToken } = options

	async function handleRequest(request: Request): Promise<Response> {
		const url = new URL(request.url)
		const route = resolveRoute(url.pathname)

		if (!route) {
			return Response.json({ error: 'Not found' }, { status: 404 })
		}

		if (route === 'content') {
			return handleContent(request, tursoUrl, tursoAuthToken)
		}

		if (route === 'config') {
			return handleConfig(request, tursoUrl, tursoAuthToken)
		}

		if (route.startsWith('jobs')) {
			return handleJobs(request, brainApiKey)
		}

		if (route === 'analytics') {
			return handleAnalytics(request, tursoUrl, tursoAuthToken)
		}

		if (route.startsWith('forms')) {
			return handleForms(request, tursoUrl, tursoAuthToken)
		}

		if (route === 'sdk-status') {
			const brainBase = globalThis.process?.env?.BRAIN_API_URL ?? 'https://brain.yourapp.com'
			const res = await fetch(`${brainBase}/api/sdk-versions`)
			const data = await res.json()
			return Response.json(data, { status: res.status })
		}

		return Response.json({ error: 'Not found' }, { status: 404 })
	}

	return {
		GET: handleRequest,
		POST: handleRequest,
	}
}
