import { eq, desc } from 'drizzle-orm'
import { blogPosts, socialPosts } from '@growth-engine/types/schema'
import { getClientDb } from '../db'

const CACHE_HEADERS = {
	'Cache-Control': 's-maxage=60, stale-while-revalidate=300',
}

export async function handleContent(
	request: Request,
	tursoUrl: string,
	tursoAuthToken: string,
): Promise<Response> {
	try {
		const url = new URL(request.url)
		const type = url.searchParams.get('type')
		const slug = url.searchParams.get('slug')
		const platform = url.searchParams.get('platform')

		const db = getClientDb(tursoUrl, tursoAuthToken)

		if (type === 'blog') {
			if (slug) {
				const post = await db
					.select()
					.from(blogPosts)
					.where(eq(blogPosts.slug, slug))
					.limit(1)
				return Response.json(post[0] ?? null, { headers: CACHE_HEADERS })
			}

			const posts = await db
				.select()
				.from(blogPosts)
				.where(eq(blogPosts.status, 'published'))
				.orderBy(desc(blogPosts.createdAt))
				.limit(20)

			return Response.json(posts, { headers: CACHE_HEADERS })
		}

		if (type === 'social') {
			if (platform === 'instagram' || platform === 'linkedin' || platform === 'facebook') {
				const posts = await db
					.select()
					.from(socialPosts)
					.where(eq(socialPosts.platform, platform))
					.orderBy(desc(socialPosts.createdAt))
					.limit(20)
				return Response.json(posts, { headers: CACHE_HEADERS })
			}

			const posts = await db
				.select()
				.from(socialPosts)
				.orderBy(desc(socialPosts.createdAt))
				.limit(20)

			return Response.json(posts, { headers: CACHE_HEADERS })
		}

		return Response.json({ error: 'Invalid content type' }, { status: 400 })
	} catch {
		return Response.json({ error: 'Internal server error' }, { status: 500 })
	}
}
