import { eq } from 'drizzle-orm'
import { forms, formSubmissions } from '@growth-engine/types/schema'
import type { FormField } from '@growth-engine/types'
import { getClientDb } from '../db'

export async function handleForms(
	request: Request,
	tursoUrl: string,
	tursoAuthToken: string,
): Promise<Response> {
	try {
		const url = new URL(request.url)
		const action = url.searchParams.get('action')
		const slug = url.searchParams.get('slug')

		const db = getClientDb(tursoUrl, tursoAuthToken)

		if (action === 'list') {
			const rows = await db
				.select()
				.from(forms)
				.where(eq(forms.status, 'active'))

			return Response.json(rows)
		}

		if (action === 'get' && slug) {
			const rows = await db
				.select()
				.from(forms)
				.where(eq(forms.slug, slug))
				.limit(1)

			return Response.json(rows[0] ?? null)
		}

		if (request.method === 'POST' && action === 'submit' && slug) {
			const body = (await request.json()) as { data?: Record<string, unknown> }
			const data = body.data

			if (!data || typeof data !== 'object') {
				return Response.json({ error: 'Missing or invalid data field' }, { status: 400 })
			}

			// Look up the form definition
			const formRows = await db
				.select()
				.from(forms)
				.where(eq(forms.slug, slug))
				.limit(1)

			const form = formRows[0]
			if (!form) {
				return Response.json({ error: 'Form not found' }, { status: 404 })
			}

			// Validate required fields
			const fields = JSON.parse(form.fields) as FormField[]
			const missingFields: string[] = []

			for (const field of fields) {
				if (field.required) {
					const value = data[field.name]
					if (value === undefined || value === null || value === '') {
						missingFields.push(field.label)
					}
				}
			}

			if (missingFields.length > 0) {
				return Response.json(
					{ error: `Missing required fields: ${missingFields.join(', ')}` },
					{ status: 400 },
				)
			}

			const id = crypto.randomUUID()

			await db.insert(formSubmissions).values({
				id,
				formId: form.id,
				data: JSON.stringify(data),
				createdAt: new Date(),
			})

			return Response.json({ ok: true, id })
		}

		return Response.json({ error: 'Invalid action' }, { status: 400 })
	} catch {
		return Response.json({ error: 'Internal server error' }, { status: 500 })
	}
}
